// User represents the user record in the database (Entity/Model) type User struct { ID uint `gorm:"primaryKey;autoIncrement" json:"userId"` Username string `gorm:"type:varchar(100);not null" json:"username"` Email string `gorm:"type:varchar(100);uniqueIndex;not null" json:"email"` Password string `gorm:"type:varchar(255);not null" json:"-"` // Hide password when parse/marshal JSON Role string `gorm:"type:varchar(50);not null;default:'member'" json:"role"` // manager or member IsVerified bool `gorm:"not null;default:false" json:"isVerified"` CreatedAt time.Time `json:"createdAt"` UpdatedAt time.Time `json:"updatedAt"` DeletedAt gorm.DeletedAt `gorm:"index" json:"-"` }

import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerApi } from "../api/authApi";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword, validateUsername } from "../utils/validators";

export default function RegisterPage() {
  const navigate = useNavigate();
  const { pushToast } = useToast();
  const [form, setForm] = useState({
    username: "",
    email: "",
    password: "",
  });
  const [touched, setTouched] = useState({
    username: false,
    email: false,
    password: false,
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const usernameError = validateUsername(form.username);
  const emailError = validateEmail(form.email);
  const passwordError = validatePassword(form.password);
  const hasFieldErrors = Boolean(usernameError || emailError || passwordError);

  const onChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ username: true, email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSuccess("");
    setSubmitting(true);

    try {
      await registerApi(form);
      setSuccess("Registration successful. Please verify your email within 5 minutes. Redirecting to login...");
      pushToast("Registration successful. Check your email for the verification link.", "success");
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">Member Onboarding</p>
        <h2>Create Account</h2>
        <p>
          Register as a member account, then verify your email link to activate secure login access.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Register</h2>
        <p className="muted page-lead">Your role is assigned as member at sign-up.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <input
            type="text"
            placeholder="Username"
            value={form.username}
            onChange={(e) => onChange("username", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, username: true }))}
            className={touched.username && usernameError ? "input-error" : ""}
            required
          />
          {touched.username && usernameError && <p className="field-error">{usernameError}</p>}
          <input
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={(e) => onChange("email", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password (min 6 chars)"
            value={form.password}
            onChange={(e) => onChange("password", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            minLength={6}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Creating..." : "Register"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {success && <div className="state-card">{success}</div>}
        <p className="muted auth-switch">
          Already have account? <Link to="/login">Login here</Link>
        </p>
      </section>
    </section>
  );
}

import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerApi } from "../api/authApi";
import { useToast } from "../context/ToastContext";
import { validateEmail, validatePassword, validateUsername } from "../utils/validators";

export default function RegisterPage() {
  const navigate = useNavigate();
  const { pushToast } = useToast();
  const [form, setForm] = useState({
    username: "",
    email: "",
    password: "",
    role: "member",
  });
  const [touched, setTouched] = useState({
    username: false,
    email: false,
    password: false,
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [submitting, setSubmitting] = useState(false);

  const usernameError = validateUsername(form.username);
  const emailError = validateEmail(form.email);
  const passwordError = validatePassword(form.password);
  const hasFieldErrors = Boolean(usernameError || emailError || passwordError);

  const onChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const onSubmit = async (event) => {
    event.preventDefault();
    setTouched({ username: true, email: true, password: true });
    if (hasFieldErrors) {
      setError("Please fix form errors before submitting");
      return;
    }

    setError("");
    setSuccess("");
    setSubmitting(true);

    try {
      await registerApi(form);
      setSuccess("Registration successful. Please verify your email within 5 minutes. Redirecting to login...");
      pushToast("Registration successful. Check your email for the verification link.", "success");
      setTimeout(() => navigate("/login"), 1000);
    } catch (err) {
      setError(err.message);
      pushToast(err.message, "error");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <section className="auth-layout">
      <aside className="auth-hero">
        <p className="auth-kicker">User Onboarding</p>
        <h2>Create Account</h2>
        <p>
          Register your account, then verify your email link to activate secure login access. Choose your capability role below.
        </p>
      </aside>

      <section className="card auth-card">
        <h2>Register</h2>
        <p className="muted page-lead">Select your account capability.</p>
        <form className="form-grid" onSubmit={onSubmit}>
          <select 
            value={form.role}
            onChange={(e) => onChange("role", e.target.value)}
            className="input-select"
          >
            <option value="member">Member (Read-only Team Access)</option>
            <option value="manager">Manager (Can Create/Manage Teams)</option>
          </select>
          <input
            type="text"
            placeholder="Username"
            value={form.username}
            onChange={(e) => onChange("username", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, username: true }))}
            className={touched.username && usernameError ? "input-error" : ""}
            required
          />
          {touched.username && usernameError && <p className="field-error">{usernameError}</p>}
          <input
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={(e) => onChange("email", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
            className={touched.email && emailError ? "input-error" : ""}
            required
          />
          {touched.email && emailError && <p className="field-error">{emailError}</p>}
          <input
            type="password"
            placeholder="Password (min 6 chars)"
            value={form.password}
            onChange={(e) => onChange("password", e.target.value)}
            onBlur={() => setTouched((prev) => ({ ...prev, password: true }))}
            className={touched.password && passwordError ? "input-error" : ""}
            minLength={6}
            required
          />
          {touched.password && passwordError && <p className="field-error">{passwordError}</p>}
          <button className="primary" type="submit" disabled={submitting || hasFieldErrors}>
            {submitting ? "Creating..." : "Register"}
          </button>
        </form>
        {error && <p className="error">{error}</p>}
        {success && <div className="state-card">{success}</div>}
        <p className="muted auth-switch">
          Already have account? <Link to="/login">Login here</Link>
        </p>
      </section>
    </section>
  );
}

package domain

// UserRef is a read-only mapping to auth service users table.
type UserRef struct {
	ID   uint   `gorm:"column:id;primaryKey"`
	Role string `gorm:"column:role"`
}

func (UserRef) TableName() string {
	return "users"
}

package repository

import (
	"team-management-service/internal/domain"

	"gorm.io/gorm"
)

// UserRepository provides read-only access to global user records.
type UserRepository interface {
	FindByID(id uint) (*domain.UserRef, error)
}

type userRepositoryImpl struct {
	db *gorm.DB
}

func NewUserRepository(db *gorm.DB) UserRepository {
	return &userRepositoryImpl{db: db}
}

func (r *userRepositoryImpl) FindByID(id uint) (*domain.UserRef, error) {
	var user domain.UserRef
	err := r.db.First(&user, id).Error
	if err != nil {
		return nil, err
	}
	return &user, nil
}
